import React from "react";
import Navbar from 'react-bootstrap/Navbar';
import Nav from 'react-bootstrap/Nav';
import { withRouter } from 'react-router-dom';
import "../styles/header.css";
import "../index.css";

class Header extends React.Component {
  render() {
    return (
      <div >
        <Navbar className="header" collapseOnSelect expand="sm" fixed="top">
            <Navbar.Brand href="/">
            <img
                src={require("../images/AR.png")}
                width="50"
                height="45"
            />
            </Navbar.Brand>
            <Navbar.Toggle aria-controls="basic-navbar-nav" styles={{border:"20px"}}/>
            <Navbar.Collapse id="responsive-navbar-nav">
                <Nav className="mr-auto">
                <Nav.Link className="header-content" href="/aboutMe">About Me</Nav.Link>
                <Nav.Link className="header-content" href="/reviews">Film Reviews</Nav.Link>
                <Nav.Link className="header-content" href="/portfolio">Portfolio</Nav.Link>
                <Nav.Link className="header-content" href="/contact">Contact</Nav.Link>
                </Nav>
            </Navbar.Collapse>
      </Navbar>
      </div>
    );
  }
}
export default withRouter(Header);
